public class ShippingInfo
{
    public string Name { get; set; } = "";
    public string Address { get; set; } = "";
    public string City { get; set; } = "";
    public string ZipCode { get; set; } = "";
}

public class PaymentInfo
{
    public string CardNumber { get; set; } = "";
    public string ExpiryDate { get; set; } = "";
}

public class Order
{
    public ShippingInfo Shipping { get; set; } = new();
    public PaymentInfo Payment { get; set; } = new();
}

@* Collects shipping address fields with basic validation on Name and Address. *@

<div class="shipping-step">
    <h3>Shipping Information</h3>

    <label>
        Name
        <input type="text" value="@Shipping.Name"
               @onchange="(e) => Shipping.Name = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Address
        <input type="text" value="@Shipping.Address"
               @onchange="(e) => Shipping.Address = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        City
        <input type="text" value="@Shipping.City"
               @onchange="(e) => Shipping.City = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Zip Code
        <input type="text" value="@Shipping.ZipCode"
               @onchange="(e) => Shipping.ZipCode = e.Value?.ToString() ?? string.Empty" />
    </label>

    @if (!string.IsNullOrWhiteSpace(_validationMessage))
    {
        <p class="validation-error">@_validationMessage</p>
    }

    <button @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public ShippingInfo Shipping { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? _validationMessage;

    private async Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(Shipping.Name) || string.IsNullOrWhiteSpace(Shipping.Address))
        {
            _validationMessage = "Name and Address are required.";
            return;
        }

        _validationMessage = null;
        await OnNext.InvokeAsync();
    }
}

@* Collects payment details; offers Back and Place Order actions. *@

<div class="payment-step">
    <h3>Payment Information</h3>

    <label>
        Card Number
        <input type="text" value="@Payment.CardNumber"
               @onchange="(e) => Payment.CardNumber = e.Value?.ToString() ?? string.Empty" />
    </label>

    <label>
        Expiry Date
        <input type="text" value="@Payment.ExpiryDate"
               @onchange="(e) => Payment.ExpiryDate = e.Value?.ToString() ?? string.Empty" />
    </label>

    <button @onclick="OnBack">Back</button>
    <button @onclick="OnPlaceOrder">Place Order</button>
</div>

@code {
    [Parameter, EditorRequired] public PaymentInfo Payment { get; set; } = default!;
    [Parameter] public EventCallback OnBack { get; set; }
    [Parameter] public EventCallback OnPlaceOrder { get; set; }
}

@* Orchestrates a two-step checkout: Shipping → Payment → order submission. *@

<div class="checkout-wizard">
    @if (_step == Step.Shipping)
    {
        <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
    }
    else
    {
        <PaymentStep Payment="_order.Payment"
                     OnBack="GoToShipping"
                     OnPlaceOrder="HandlePlaceOrder" />
    }
</div>

@code {
    /// <summary>Fires when the user completes checkout with a finished Order.</summary>
    [Parameter] public EventCallback<Order> OnOrderPlaced { get; set; }

    private Order _order = new();
    private Step _step = Step.Shipping;

    private enum Step { Shipping, Payment }

    private void GoToPayment() => _step = Step.Payment;
    private void GoToShipping() => _step = Step.Shipping;

    private async Task HandlePlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

